export const KHOA_REPORTS: { khoa: string; phanI: string; phanII: string; phanIII: string }[] = [{"khoa": "Khoa Kinh doanh", "phanI": "Khoa Kinh doanh quản lý 4 ngành (Quản trị DN vừa và nhỏ, Digital Marketing, Quản trị khách sạn, Chăm sóc sắc đẹp) với 1.142 sinh viên nhập học lũy kế K23-K25. Đang học tại T6/2026: 348 SV (30.5%). Biến động năm học 2025-2026: 59 ca thôi học, 42 ca bảo lưu, 11 SV nghỉ học dài ngày lũy kế. Theo báo cáo riêng của Khoa, ngành Digital Marketing có quy mô lớn nhất (363 SV quản lý trực tiếp trong kỳ) và tỷ lệ Drop toàn năm cao nhất khối (33%, tỷ lệ gắn kết 63%); ngành Chăm sóc sắc đẹp ổn định nhất (Drop ~2-4,4%/kỳ, tỷ lệ gắn kết 73,6%).", "phanII": "Rào cản chung khối Kinh doanh: (1) Kinh tế — lạm phát 2 năm gần đây, sinh viên phải đi làm sớm giảm thời gian học; (2) Sai định hướng nghề nghiệp — một bộ phận sinh viên bị điều hướng ngành (vd. Logistics → QTDN, K25) không đồng thuận nên nghỉ; (3) Chuyển trường/du học/xuất khẩu lao động — không phản ánh chất lượng đào tạo nhưng vẫn làm giảm quy mô; (4) Học lực yếu, nợ môn, lười học ở một bộ phận sinh viên. Cảnh báo sớm của Khoa còn bị động do nhiều số điện thoại sai/thuê bao/phụ huynh không phản hồi.", "phanIII": "Đề xuất khối Kinh doanh: (1) Xây dựng dashboard cảnh báo Drop thời gian thực theo 4 tiêu chí (nghỉ học, học lực, học phí, điểm danh); (2) Tăng cường cố vấn học tập — theo dõi từng sinh viên nguy cơ, liên hệ phụ huynh ngay khi nghỉ nhiều buổi; (3) Mở rộng chính sách hỗ trợ tài chính — gia hạn học phí, học bổng, quỹ khẩn cấp cho sinh viên khó khăn kinh tế; (4) Tăng trải nghiệm nghề nghiệp sớm — việc làm part-time đúng chuyên ngành, dự án có mentor doanh nghiệp; (5) Ban hành quy trình xử lý nghỉ dài ngày thống nhất toàn khối."}, {"khoa": "Khoa Công nghệ - Thiết kế", "phanI": "Khoa Công nghệ - Thiết kế quản lý 3 ngành (Công nghệ ô tô, Thiết kế đồ hoạ, Ứng dụng phần mềm) với 1.123 sinh viên nhập học lũy kế K23-K25. Đang học tại T6/2026: 427 SV (38.0%). Biến động năm học: 70 ca thôi học, 31 ca bảo lưu, 67 SV nghỉ học dài ngày lũy kế — cao nhất khối là Công nghệ ô tô (35 SV NHDN, tỷ lệ thôi học lũy kế 11,83%, riêng K25 CĐCQ đã có 24 SV NHDN ngay năm đầu).", "phanII": "Rào cản chung khối Công nghệ - Thiết kế: (1) Chương trình học kỳ đầu còn nặng lý thuyết, chưa tạo trải nghiệm thực hành xưởng/phần mềm sớm; (2) Chi phí ẩn cao — máy tính cấu hình cao (Thiết kế đồ hoạ), bản quyền phần mềm Adobe gặp vấn đề; (3) Sinh viên chưa từng lập trình/thiết kế dễ rớt chuỗi môn cơ sở ngành, đặc biệt sinh viên hệ 9+ chưa có định hướng nghề nghiệp rõ ràng; (4) Thông tin liên lạc phụ huynh từ lúc tuyển sinh nhiều trường hợp sai lệch, giảm hiệu quả cảnh báo sớm; (5) Nhân sự giảng dạy một số ngành còn mỏng (Thiết kế đồ hoạ chưa có đủ giảng viên cơ hữu).", "phanIII": "Đề xuất khối Công nghệ - Thiết kế: (1) Thắt chặt kiểm tra thông tin liên lạc phụ huynh ngay tuần đầu nhập học; (2) Tổ chức trải nghiệm thực hành xưởng/phần mềm sớm trong học kỳ 1 thay vì dồn lý thuyết; (3) Đầu tư bản quyền phần mềm chuyên ngành (Adobe CC) và nâng cấp trang thiết bị xưởng; (4) Tuyển bổ sung giảng viên cơ hữu, đặc biệt ngành Thiết kế đồ hoạ; (5) Chăm sóc đặc biệt nhóm K25 Công nghệ ô tô — nhóm nguy cơ cao nhất khối."}, {"khoa": "Khoa Ngôn ngữ", "phanI": "Khoa Ngôn ngữ (Ngôn ngữ và Văn hóa Quốc tế) quản lý 4 ngành (Tiếng Trung, Phiên dịch tiếng Anh thương mại, Tiếng Hàn, Tiếng Nhật) với 1.064 sinh viên nhập học lũy kế K23-K25. Đang học tại T6/2026: 255 SV (24.0%). Biến động năm học: 39 ca thôi học, 23 ca bảo lưu, 3 SV nghỉ học dài ngày lũy kế. Ngành Tiếng Trung có biến động mạnh nhất, riêng K25 CĐCQ giảm từ đỉnh 239 SV (T10/2025) xuống 128 SV chỉ trong 1 tháng (T11/2025); ngành Phiên dịch tiếng Anh thương mại và Tiếng Hàn có mô hình cảnh báo sớm (vắng quá 2 buổi liên hệ ngay gia đình) hoạt động hiệu quả nhất trường.", "phanII": "Rào cản chung khối Ngôn ngữ: (1) Ghi danh không thực chất ở tân sinh viên — một bộ phận đăng ký chỉ để hoãn nghĩa vụ quân sự, đã học trường khác, hoặc dự định du học/xuất khẩu lao động, không nhằm mục tiêu học tập thật sự (đặc biệt rõ ở Tiếng Trung K25); (2) Sốc chuyên ngành đầu khóa — khối lượng từ vựng/ngữ pháp/Kanji-Hán tự tăng nhanh khiến tân sinh viên chưa có nền tảng dễ nản; (3) Quý sau Tết Nguyên đán (T1-T3) là điểm rơi rủi ro theo mùa vụ do tác động tâm lý và kế hoạch gia đình; (4) Khó liên lạc gia đình — số điện thoại sai, phụ huynh không theo sát hoặc không quản được con.", "phanIII": "Đề xuất khối Ngôn ngữ: (1) Siết chặt xác minh nhập học thực chất trong tuần đầu (gọi điện/gặp trực tiếp) trước khi xếp lớp — ưu tiên áp dụng ngay cho Tiếng Trung K25; (2) Xây lộ trình làm quen ngôn ngữ chuyên ngành cho tân sinh viên trong 2-3 tuần đầu; (3) Tăng cường hoạt động gắn kết văn hóa (CLB, sự kiện) vào đúng điểm rơi Quý sau Tết; (4) Chuẩn hóa trường \"lý do thôi học\" trên CMS toàn khối thay vì lưu hồ sơ riêng từng GVCN; (5) Nhân rộng mô hình cảnh báo sớm (vắng quá 2 buổi liên hệ ngay) của Tiếng Anh/Tiếng Hàn sang Tiếng Trung và bổ sung báo cáo định tính cho ngành Tiếng Nhật."}];
